SELECT *
FROM permission
WHERE document_id = #{documentId}
    AND user_id = #{userId}
    AND permission_type IN ('editor', 'owner')
    AND is_deleted = 0

SELECT *
FROM permission
WHERE document_id = #{documentId}
    AND user_id = #{userId}
